// A JNA Library to expose the extern-C FFI definitions.
// This is an implementation detail which will be called internally by the public API.

// For large crates we prevent `MethodTooLargeException` (see #2340)
// N.B. the name of the extension is very misleading, since it is
// rather `InterfaceTooLargeException`, caused by too many methods
// in the interface for large crates.
//
// By splitting the otherwise huge interface into two parts
// * UniffiLib (this)
// * IntegrityCheckingUniffiLib
// And all checksum methods are put into `IntegrityCheckingUniffiLib`
// we allow for ~2x as many methods in the UniffiLib interface.
//
// Note: above all written when we used JNA's `loadIndirect` etc.
// We now use JNA's "direct mapping" - unclear if same considerations apply exactly.
internal object IntegrityCheckingUniffiLib {
    init {
        Native.register(IntegrityCheckingUniffiLib::class.java, findLibraryName(componentName = "wick_ffi"))
        uniffiCheckContractApiVersion(this)
        uniffiCheckApiChecksums(this)
    }

    external fun uniffi_wick_ffi_checksum_func_wick_ffi_version(): Short

    external fun uniffi_wick_ffi_checksum_method_bundlerepo_store_dir(): Short

    external fun uniffi_wick_ffi_checksum_method_downloadprogresssink_on_progress(): Short

    external fun uniffi_wick_ffi_checksum_method_modalitysink_on_text_tokens(): Short

    external fun uniffi_wick_ffi_checksum_method_modalitysink_on_audio_frames(): Short

    external fun uniffi_wick_ffi_checksum_method_modalitysink_on_done(): Short

    external fun uniffi_wick_ffi_checksum_method_session_append_text(): Short

    external fun uniffi_wick_ffi_checksum_method_session_append_tokens(): Short

    external fun uniffi_wick_ffi_checksum_method_session_cancel(): Short

    external fun uniffi_wick_ffi_checksum_method_session_capabilities(): Short

    external fun uniffi_wick_ffi_checksum_method_session_generate(): Short

    external fun uniffi_wick_ffi_checksum_method_session_generate_async(): Short

    external fun uniffi_wick_ffi_checksum_method_session_generate_streaming(): Short

    external fun uniffi_wick_ffi_checksum_method_session_generate_streaming_async(): Short

    external fun uniffi_wick_ffi_checksum_method_session_position(): Short

    external fun uniffi_wick_ffi_checksum_method_session_reset(): Short

    external fun uniffi_wick_ffi_checksum_method_wickengine_capabilities(): Short

    external fun uniffi_wick_ffi_checksum_method_wickengine_metadata(): Short

    external fun uniffi_wick_ffi_checksum_method_wickengine_new_session(): Short

    external fun uniffi_wick_ffi_checksum_constructor_bundlerepo_new(): Short

    external fun uniffi_wick_ffi_checksum_constructor_bundlerepo_with_progress(): Short

    external fun uniffi_wick_ffi_checksum_constructor_wickengine_from_bundle_id(): Short

