     * Cancellation: dropping the returned future fires the same
     * abort + [`Session::cancel`] pair as [`Session::generate_async`]
     * (see [`AsyncCancelGuard`]). For an in-flight decode, the loop
     * exits with [`FinishReason::Cancelled`] and the sink's `on_done`
     * fires on the blocking worker before the task completes —
     * foreign consumers get the terminal signal even though they've
     * already stopped awaiting. For a queued-but-not-started decode,
     * abort cancels the task without ever running the closure; no
     * sink callbacks fire for that case (the decode never began).
     */
    @Throws(FfiException::class)
    @Suppress("ASSIGNED_BUT_NEVER_ACCESSED_VARIABLE")
    override suspend fun `generateStreamingAsync`(
        `opts`: GenerateOpts,
        `sink`: ModalitySink,
    ): GenerateSummary =
        uniffiRustCallAsync(
            callWithHandle { uniffiHandle ->
                UniffiLib.uniffi_wick_ffi_fn_method_session_generate_streaming_async(
                    uniffiHandle,
                    FfiConverterTypeGenerateOpts.lower(`opts`),
                    FfiConverterTypeModalitySink.lower(`sink`),
                )
            },
            { future, callback, continuation -> UniffiLib.ffi_wick_ffi_rust_future_poll_rust_buffer(future, callback, continuation) },
            { future, continuation -> UniffiLib.ffi_wick_ffi_rust_future_complete_rust_buffer(future, continuation) },
            { future -> UniffiLib.ffi_wick_ffi_rust_future_free_rust_buffer(future) },
            // lift function
            { FfiConverterTypeGenerateSummary.lift(it) },
            // Error FFI converter
            FfiException.ErrorHandler,
        )

    /**
     * Current KV position — how many tokens live in the cache.
     * Atomic-backed; safe to call from a different thread while
     * `generate()` is in flight.
     */
    override fun `position`(): kotlin.UInt =
        FfiConverterUInt.lift(
            callWithHandle {
                uniffiRustCall { _status ->
                    UniffiLib.uniffi_wick_ffi_fn_method_session_position(
                        it,
                        _status,
                    )
                }
            },
        )

    /**
     * Drop cached state + resample the seed. After `reset()` the
     * session behaves like a freshly-opened one (same
     * model/tokenizer/config, no accumulated context).
     *
     * Returns `Result` so a poisoned-mutex case surfaces as an error
     * instead of panicking across the FFI boundary.
     */
    @Throws(FfiException::class)
    override fun `reset`() =
        callWithHandle {
            uniffiRustCallWithError(FfiException) { _status ->
                UniffiLib.uniffi_wick_ffi_fn_method_session_reset(
                    it,
                    _status,
                )
            }
        }

    /**
     * @suppress
     */
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeSession : FfiConverter<Session, Long> {
    override fun lower(value: Session): Long = value.uniffiCloneHandle()

    override fun lift(value: Long): Session = Session(UniffiWithHandle, value)

    override fun read(buf: ByteBuffer): Session = lift(buf.getLong())

    override fun allocationSize(value: Session) = 8UL

    override fun write(
        value: Session,
        buf: ByteBuffer,
    ) {
        buf.putLong(lower(value))
    }
}

// This template implements a class for working with a Rust struct via a handle
// to the live Rust struct on the other side of the FFI.
//
// There's some subtlety here, because we have to be careful not to operate on a Rust
// struct after it has been dropped, and because we must expose a public API for freeing
// theq Kotlin wrapper object in lieu of reliable finalizers. The core requirements are:
//
//   * Each instance holds an opaque handle to the underlying Rust struct.
//     Method calls need to read this handle from the object's state and pass it in to
//     the Rust FFI.
//
//   * When an instance is no longer needed, its handle should be passed to a
//     special destructor function provided by the Rust FFI, which will drop the
//     underlying Rust struct.
//
//   * Given an instance, calling code is expected to call the special
//     `destroy` method in order to free it after use, either by calling it explicitly
//     or by using a higher-level helper like the `use` method. Failing to do so risks
//     leaking the underlying Rust struct.
//
//   * We can't assume that calling code will do the right thing, and must be prepared
//     to handle Kotlin method calls executing concurrently with or even after a call to
//     `destroy`, and to handle multiple (possibly concurrent!) calls to `destroy`.
//
//   * We must never allow Rust code to operate on the underlying Rust struct after
//     the destructor has been called, and must never call the destructor more than once.
//     Doing so may trigger memory unsafety.
//
//   * To mitigate many of the risks of leaking memory and use-after-free unsafety, a `Cleaner`
//     is implemented to call the destructor when the Kotlin object becomes unreachable.
//     This is done in a background thread. This is not a panacea, and client code should be aware that
//      1. the thread may starve if some there are objects that have poorly performing
//     `drop` methods or do significant work in their `drop` methods.
//      2. the thread is shared across the whole library. This can be tuned by using `android_cleaner = true`,
//         or `android = true` in the [`kotlin` section of the `uniffi.toml` file](https://mozilla.github.io/uniffi-rs/kotlin/configuration.html).
//
// If we try to implement this with mutual exclusion on access to the handle, there is the
// possibility of a race between a method call and a concurrent call to `destroy`:
//
//    * Thread A starts a method call, reads the value of the handle, but is interrupted
//      before it can pass the handle over the FFI to Rust.
//    * Thread B calls `destroy` and frees the underlying Rust struct.
//    * Thread A resumes, passing the already-read handle value to Rust and triggering
//      a use-after-free.
//
// One possible solution would be to use a `ReadWriteLock`, with each method call taking
// a read lock (and thus allowed to run concurrently) and the special `destroy` method
// taking a write lock (and thus blocking on live method calls). However, we aim not to
// generate methods with any hidden blocking semantics, and a `destroy` method that might
// block if called incorrectly seems to meet that bar.
//
// So, we achieve our goals by giving each instance an associated `AtomicLong` counter to track
// the number of in-flight method calls, and an `AtomicBoolean` flag to indicate whether `destroy`
// has been called. These are updated according to the following rules:
//
//    * The initial value of the counter is 1, indicating a live object with no in-flight calls.
//      The initial value for the flag is false.
//
//    * At the start of each method call, we atomically check the counter.
//      If it is 0 then the underlying Rust struct has already been destroyed and the call is aborted.
//      If it is nonzero them we atomically increment it by 1 and proceed with the method call.
//
//    * At the end of each method call, we atomically decrement and check the counter.
//      If it has reached zero then we destroy the underlying Rust struct.
//
//    * When `destroy` is called, we atomically flip the flag from false to true.
//      If the flag was already true we silently fail.
//      Otherwise we atomically decrement and check the counter.
//      If it has reached zero then we destroy the underlying Rust struct.
//
// Astute readers may observe that this all sounds very similar to the way that Rust's `Arc<T>` works,
// and indeed it is, with the addition of a flag to guard against multiple calls to `destroy`.
//
// The overall effect is that the underlying Rust struct is destroyed only when `destroy` has been
// called *and* all in-flight method calls have completed, avoiding violating any of the expectations
// of the underlying Rust code.
//
// This makes a cleaner a better alternative to _not_ calling `destroy()` as
// and when the object is finished with, but the abstraction is not perfect: if the Rust object's `drop`
// method is slow, and/or there are many objects to cleanup, and it's on a low end Android device, then the cleaner
// thread may be starved, and the app will leak memory.
//
// In this case, `destroy`ing manually may be a better solution.
//
// The cleaner can live side by side with the manual calling of `destroy`. In the order of responsiveness, uniffi objects
// with Rust peers are reclaimed:
//
// 1. By calling the `destroy` method of the object, which calls `rustObject.free()`. If that doesn't happen:
// 2. When the object becomes unreachable, AND the Cleaner thread gets to call `rustObject.free()`. If the thread is starved then:
// 3. The memory is reclaimed when the process terminates.
//
// [1] https://stackoverflow.com/questions/24376768/can-java-finalize-an-object-when-it-is-still-in-scope/24380219
//

/**
 * Owning handle to a loaded model. Mirrors [`wick::WickEngine`];
 * `#[uniffi::Object]` requires `Arc<Self>` wrapping which matches how
 * the underlying engine is already used internally.
 */
public interface WickEngineInterface {
    /**
     * What this model accepts as input / emits as output. Derived at
     * load time from the manifest's `inference_type`.
     */
    fun `capabilities`(): ModalityCapabilities

    /**
     * Short summary of the loaded model (architecture, vocab size,
     * max context, etc.). Returns a `Clone` of the stored metadata.
     */
    fun `metadata`(): ModelMetadata

    /**
     * Open a new [`Session`] sharing this engine's model + tokenizer
     * by `Arc` clone. The returned session outlives `&self`; the
     * engine keeps the shared state live for every session it hands
     * out. Cheap — no model load, just config + state allocation.
     */
    fun `newSession`(`config`: SessionConfig): Session

    companion object
}

/**
 * Owning handle to a loaded model. Mirrors [`wick::WickEngine`];
 * `#[uniffi::Object]` requires `Arc<Self>` wrapping which matches how
 * the underlying engine is already used internally.
 */
open class WickEngine :
    Disposable,
    AutoCloseable,
    WickEngineInterface {
    /**
     * @suppress
     */
    @Suppress("UNUSED_PARAMETER")
    constructor(withHandle: UniffiWithHandle, handle: Long) {
        this.handle = handle
        this.cleanable = UniffiLib.CLEANER.register(this, UniffiCleanAction(handle))
    }

    /**
     * @suppress
     *
     * This constructor can be used to instantiate a fake object. Only used for tests. Any
     * attempt to actually use an object constructed this way will fail as there is no
     * connected Rust object.
     */
    @Suppress("UNUSED_PARAMETER")
    constructor(noHandle: NoHandle) {
        this.handle = 0
        this.cleanable = null
    }

    protected val handle: Long
    protected val cleanable: UniffiCleaner.Cleanable?

    private val wasDestroyed = AtomicBoolean(false)
    private val callCounter = AtomicLong(1)

    override fun destroy() {
        // Only allow a single call to this method.
        // TODO: maybe we should log a warning if called more than once?
        if (this.wasDestroyed.compareAndSet(false, true)) {
            // This decrement always matches the initial count of 1 given at creation time.
            if (this.callCounter.decrementAndGet() == 0L) {
                cleanable?.clean()
            }
        }
    }

    @Synchronized
    override fun close() {
        this.destroy()
    }

    internal inline fun <R> callWithHandle(block: (handle: Long) -> R): R {
        // Check and increment the call counter, to keep the object alive.
        // This needs a compare-and-set retry loop in case of concurrent updates.
        do {
            val c = this.callCounter.get()
            if (c == 0L) {
                throw IllegalStateException("${this.javaClass.simpleName} object has already been destroyed")
            }
            if (c == Long.MAX_VALUE) {
                throw IllegalStateException("${this.javaClass.simpleName} call counter would overflow")
            }
        } while (!this.callCounter.compareAndSet(c, c + 1L))
        // Now we can safely do the method call without the handle being freed concurrently.
        try {
            return block(this.uniffiCloneHandle())
        } finally {
            // This decrement always matches the increment we performed above.
            if (this.callCounter.decrementAndGet() == 0L) {
                cleanable?.clean()
            }
        }
    }

    // Use a static inner class instead of a closure so as not to accidentally
    // capture `this` as part of the cleanable's action.
    private class UniffiCleanAction(
        private val handle: Long,
    ) : Runnable {
        override fun run() {
            if (handle == 0.toLong()) {
                // Fake object created with `NoHandle`, don't try to free.
                return
            }
            uniffiRustCall { status ->
                UniffiLib.uniffi_wick_ffi_fn_free_wickengine(handle, status)
            }
        }
    }

    /**
     * @suppress
     */
    fun uniffiCloneHandle(): Long {
        if (handle == 0.toLong()) {
            throw InternalException("uniffiCloneHandle() called on NoHandle object")
        }
        return uniffiRustCall { status ->
            UniffiLib.uniffi_wick_ffi_fn_clone_wickengine(handle, status)
        }
    }

    /**
     * What this model accepts as input / emits as output. Derived at
     * load time from the manifest's `inference_type`.
     */
    override fun `capabilities`(): ModalityCapabilities =
        FfiConverterTypeModalityCapabilities.lift(
            callWithHandle {
                uniffiRustCall { _status ->
                    UniffiLib.uniffi_wick_ffi_fn_method_wickengine_capabilities(
                        it,
                        _status,
                    )
                }
            },
        )

    /**
     * Short summary of the loaded model (architecture, vocab size,
     * max context, etc.). Returns a `Clone` of the stored metadata.
     */
    override fun `metadata`(): ModelMetadata =
        FfiConverterTypeModelMetadata.lift(
            callWithHandle {
                uniffiRustCall { _status ->
                    UniffiLib.uniffi_wick_ffi_fn_method_wickengine_metadata(
                        it,
                        _status,
                    )
                }
            },
        )

    /**
     * Open a new [`Session`] sharing this engine's model + tokenizer
     * by `Arc` clone. The returned session outlives `&self`; the
     * engine keeps the shared state live for every session it hands
     * out. Cheap — no model load, just config + state allocation.
     */
    override fun `newSession`(`config`: SessionConfig): Session =
        FfiConverterTypeSession.lift(
            callWithHandle {
                uniffiRustCall { _status ->
                    UniffiLib.uniffi_wick_ffi_fn_method_wickengine_new_session(
                        it,
                        FfiConverterTypeSessionConfig.lower(`config`),
                        _status,
                    )
                }
            },
        )

    companion object {
        /**
         * Load a model by LeapBundles ID + quantization selector, e.g.
         * `from_bundle_id("LFM2-1.2B-GGUF", "Q4_0", config)`. Resolves
         * to the matching `<bundle_id>/<quant>.json` manifest under
         * `huggingface.co/LiquidAI/LeapBundles` and downloads whatever
         * isn't already in `config.bundle_repo`'s on-disk cache.
         *
         * `config.bundle_repo` must be set; otherwise this returns an
         * [`FfiError::Backend`] telling the caller to construct a
         * [`BundleRepo`] and attach it. Idempotent across calls — the
         * repo's cache deduplicates subsequent downloads.
         *
         * Blocking: this call fetches over the network on first run +
         * opens / parses the GGUF. Foreign async runtimes should wrap
         * the call in `spawn_blocking` / its equivalent. (An async
         * counterpart matching `generate_async` could be added later;
         * not in this PR.)
         */
        @Throws(FfiException::class)
        fun `fromBundleId`(
            `bundleId`: kotlin.String,
            `quant`: kotlin.String,
            `config`: EngineConfig,
        ): WickEngine =
            FfiConverterTypeWickEngine.lift(
                uniffiRustCallWithError(FfiException) { _status ->
                    UniffiLib.uniffi_wick_ffi_fn_constructor_wickengine_from_bundle_id(
                        FfiConverterString.lower(`bundleId`),
                        FfiConverterString.lower(`quant`),
                        FfiConverterTypeEngineConfig.lower(`config`),
                        _status,
                    )
                },
            )

        /**
         * Async variant of [`WickEngine::from_bundle_id`] — offloads the
         * manifest + GGUF download and the engine construction onto a
         * tokio blocking worker so the caller's async context isn't
         * stalled. Foreign async runtimes (Kotlin coroutines, Swift
         * `async`, Python `asyncio`) `.await` it directly.
         *
         * `config.bundle_repo` must be set (same constraint as the sync
         * twin); construct a [`BundleRepo`] rooted at a persistent cache
         * directory and attach it to the config before calling.
         *
         * Cancellation semantics (weaker than [`Session::generate_async`]):
         * dropping the returned future drops the [`AbortOnDrop`] guard,
         * which calls `AbortHandle::abort` on the spawned task. That
         * cancels the task if it's still queued on tokio's blocking
         * pool, so a not-yet-started download never runs. But if the
         * task has started, abort is a no-op — the download is a
         * `reqwest::blocking` call with no cooperative cancel point,
         * and wick's engine-construction code (tokenizer build, model
         * load, KV alloc) also isn't interruptible. In that case the
         * task runs to completion and the engine is constructed then
         * dropped; the downloaded bundle stays cached, so the caller's
         * next attempt starts from that cache hit. Bandwidth isn't
         * wasted, it's just shifted.
         *
         * `JoinError` from a panicking blocking closure surfaces as
         * [`FfiError::Backend`] with a diagnostic prefix, same as
         * [`Session::generate_async`].
         */
        @Throws(FfiException::class)
        @Suppress("ASSIGNED_BUT_NEVER_ACCESSED_VARIABLE")
        suspend fun `fromBundleIdAsync`(
            `bundleId`: kotlin.String,
            `quant`: kotlin.String,
            `config`: EngineConfig,
        ): WickEngine =
            uniffiRustCallAsync(
                UniffiLib.uniffi_wick_ffi_fn_constructor_wickengine_from_bundle_id_async(
                    FfiConverterString.lower(`bundleId`),
                    FfiConverterString.lower(`quant`),
                    FfiConverterTypeEngineConfig.lower(`config`),
                ),
                { future, callback, continuation -> UniffiLib.ffi_wick_ffi_rust_future_poll_u64(future, callback, continuation) },
                { future, continuation -> UniffiLib.ffi_wick_ffi_rust_future_complete_u64(future, continuation) },
                { future -> UniffiLib.ffi_wick_ffi_rust_future_free_u64(future) },
                // lift function
                { FfiConverterTypeWickEngine.lift(it) },
                // Error FFI converter
                FfiException.ErrorHandler,
            )

        /**
         * Load a model from a local filesystem path. Accepts the same
         * inputs as the native [`wick::WickEngine::from_path`]: a bare
         * `.gguf`, a LeapBundles `.json` manifest, or a directory
         * containing exactly one `.json` manifest.
         *
         * If the manifest carries `http(s)://` URLs for its files,
         * `config.bundle_repo` must be set — otherwise those URLs fail
         * to resolve. For a pure-local workflow (bundle already on
         * disk) leave `bundle_repo = None`.
         */
        @Throws(FfiException::class)
        fun `fromPath`(
            `path`: kotlin.String,
            `config`: EngineConfig,
        ): WickEngine =
            FfiConverterTypeWickEngine.lift(
                uniffiRustCallWithError(FfiException) { _status ->
                    UniffiLib.uniffi_wick_ffi_fn_constructor_wickengine_from_path(
                        FfiConverterString.lower(`path`),
                        FfiConverterTypeEngineConfig.lower(`config`),
                        _status,
                    )
                },
            )
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeWickEngine : FfiConverter<WickEngine, Long> {
    override fun lower(value: WickEngine): Long = value.uniffiCloneHandle()

    override fun lift(value: Long): WickEngine = WickEngine(UniffiWithHandle, value)

    override fun read(buf: ByteBuffer): WickEngine = lift(buf.getLong())

    override fun allocationSize(value: WickEngine) = 8UL

    override fun write(
        value: WickEngine,
        buf: ByteBuffer,
    ) {
        buf.putLong(lower(value))
    }
}

/**
 * Per-engine configuration at load time. Mirrors [`wick::EngineConfig`]
 * with `u64` fields (UniFFI doesn't marshal `usize`).
 */
data class EngineConfig(
    /**
     * KV-cache capacity in tokens. Capped by the model's own
     * `max_seq_len`. Pass `0` to use the model's full declared
     * `max_seq_len` (translated to `usize::MAX` internally, then
     * capped by the loader).
     */
    var `contextSize`: kotlin.ULong,
    var `backend`: BackendPreference,
    /**
     * Bundle repository for resolving `http(s)://` URLs in manifests
     * (or for [`WickEngine::from_bundle_id`]). `None` means "remote
     * URLs will fail with an error"; set this to a [`BundleRepo`]
     * rooted at a persistent cache directory to enable remote
     * downloads. Construct the repo once + reuse it across engine
     * loads so its HTTP client pool + on-disk cache are shared.
     */
    var `bundleRepo`: BundleRepo?,
) : Disposable {
    @Suppress("UNNECESSARY_SAFE_CALL") // codegen is much simpler if we unconditionally emit safe calls here
    override fun destroy() {
        Disposable.destroy(
            this.`contextSize`,
            this.`backend`,
            this.`bundleRepo`,
        )
    }

    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeEngineConfig : FfiConverterRustBuffer<EngineConfig> {
    override fun read(buf: ByteBuffer): EngineConfig =
        EngineConfig(
            FfiConverterULong.read(buf),
            FfiConverterTypeBackendPreference.read(buf),
            FfiConverterOptionalTypeBundleRepo.read(buf),
        )

    override fun allocationSize(value: EngineConfig) =
        (
            FfiConverterULong.allocationSize(value.`contextSize`) +
                FfiConverterTypeBackendPreference.allocationSize(value.`backend`) +
                FfiConverterOptionalTypeBundleRepo.allocationSize(value.`bundleRepo`)
        )

    override fun write(
        value: EngineConfig,
        buf: ByteBuffer,
    ) {
        FfiConverterULong.write(value.`contextSize`, buf)
        FfiConverterTypeBackendPreference.write(value.`backend`, buf)
        FfiConverterOptionalTypeBundleRepo.write(value.`bundleRepo`, buf)
    }
}

/**
 * Per-call decode options. Mirrors [`wick::GenerateOpts`].
 *
 * `flush_every_tokens` / `flush_every_ms` are accepted but have no
 * effect under the synchronous [`Session::generate`] — they're
 * meaningful once streaming (foreign-trait `ModalitySink`) lands
 * in a follow-up PR. Including them in the record now keeps the FFI
 * surface stable across that transition.
 */
data class GenerateOpts(
    var `maxTokens`: kotlin.UInt,
    var `temperature`: kotlin.Float,
    var `topP`: kotlin.Float,
    var `topK`: kotlin.UInt,
    /**
     * Reserved — the sampler doesn't implement rep-penalty yet.
     */
    var `repetitionPenalty`: kotlin.Float,
    /**
     * Early-stop IDs (EOS / instruction markers / end-of-turn).
     */
    var `stopTokens`: List<kotlin.UInt>,
    /**
     * Ignored under synchronous generate; reserved for streaming.
     */
    var `flushEveryTokens`: kotlin.UInt,
    /**
     * Ignored under synchronous generate; reserved for streaming.
     */
    var `flushEveryMs`: kotlin.UInt,
) {
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeGenerateOpts : FfiConverterRustBuffer<GenerateOpts> {
    override fun read(buf: ByteBuffer): GenerateOpts =
        GenerateOpts(
            FfiConverterUInt.read(buf),
            FfiConverterFloat.read(buf),
            FfiConverterFloat.read(buf),
            FfiConverterUInt.read(buf),
            FfiConverterFloat.read(buf),
            FfiConverterSequenceUInt.read(buf),
            FfiConverterUInt.read(buf),
            FfiConverterUInt.read(buf),
        )

    override fun allocationSize(value: GenerateOpts) =
        (
            FfiConverterUInt.allocationSize(value.`maxTokens`) +
                FfiConverterFloat.allocationSize(value.`temperature`) +
                FfiConverterFloat.allocationSize(value.`topP`) +
                FfiConverterUInt.allocationSize(value.`topK`) +
                FfiConverterFloat.allocationSize(value.`repetitionPenalty`) +
                FfiConverterSequenceUInt.allocationSize(value.`stopTokens`) +
                FfiConverterUInt.allocationSize(value.`flushEveryTokens`) +
                FfiConverterUInt.allocationSize(value.`flushEveryMs`)
        )

    override fun write(
        value: GenerateOpts,
        buf: ByteBuffer,
    ) {
        FfiConverterUInt.write(value.`maxTokens`, buf)
        FfiConverterFloat.write(value.`temperature`, buf)
        FfiConverterFloat.write(value.`topP`, buf)
        FfiConverterUInt.write(value.`topK`, buf)
        FfiConverterFloat.write(value.`repetitionPenalty`, buf)
        FfiConverterSequenceUInt.write(value.`stopTokens`, buf)
        FfiConverterUInt.write(value.`flushEveryTokens`, buf)
        FfiConverterUInt.write(value.`flushEveryMs`, buf)
    }
}

/**
 * Bundle of everything a synchronous `generate` call produces:
 * the generated token IDs plus the decode summary. The two are
 * returned together so callers don't have to manage a separate
 * callback channel; streaming (per-chunk delivery) lands in PR 4.
 */
data class GenerateOutput(
    /**
     * Generated token IDs, in order, not including any prompt
     * tokens. Decode with [`wick::tokenizer::BpeTokenizer`] on the
     * Rust side or (once exposed) through a tokenizer handle on the
     * FFI side.
     */
    var `tokens`: List<kotlin.UInt>,
    var `summary`: GenerateSummary,
) {
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeGenerateOutput : FfiConverterRustBuffer<GenerateOutput> {
    override fun read(buf: ByteBuffer): GenerateOutput =
        GenerateOutput(
            FfiConverterSequenceUInt.read(buf),
            FfiConverterTypeGenerateSummary.read(buf),
        )

    override fun allocationSize(value: GenerateOutput) =
        (
            FfiConverterSequenceUInt.allocationSize(value.`tokens`) +
                FfiConverterTypeGenerateSummary.allocationSize(value.`summary`)
        )

    override fun write(
        value: GenerateOutput,
        buf: ByteBuffer,
    ) {
        FfiConverterSequenceUInt.write(value.`tokens`, buf)
        FfiConverterTypeGenerateSummary.write(value.`summary`, buf)
    }
}

/**
 * Decode-run metadata. Mirrors [`wick::GenerateSummary`].
 */
data class GenerateSummary(
    var `tokensGenerated`: kotlin.UInt,
    var `promptEvalTokens`: kotlin.UInt,
