/**
 * KV-cache compression mode. Mirrors [`wick::kv_cache::KvCompression`].
 * `TurboQuant` is honored by the CPU backend only; Metal / GPU ignore
 * the setting and use the f32 path.
 */
sealed class KvCompression {
    /**
     * No compression — f32 keys and values (default).
     */
    object None : KvCompression()

    /**
     * TurboQuant compression. Both `keys` + `values` true is the
     * production configuration; toggling them individually is
     * primarily for debugging the drift contribution of each side.
     * `seed` drives the per-layer randomized Hadamard rotations.
     */
    data class TurboQuant(
        val `seed`: kotlin.ULong,
        val `keys`: kotlin.Boolean,
        val `values`: kotlin.Boolean,
    ) : KvCompression() {
        companion object
    }

    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeKvCompression : FfiConverterRustBuffer<KvCompression> {
    override fun read(buf: ByteBuffer): KvCompression =
        when (buf.getInt()) {
            1 -> {
                KvCompression.None
            }

            2 -> {
                KvCompression.TurboQuant(
                    FfiConverterULong.read(buf),
                    FfiConverterBoolean.read(buf),
                    FfiConverterBoolean.read(buf),
                )
            }

            else -> {
                throw RuntimeException("invalid enum value, something is very wrong!!")
            }
        }

    override fun allocationSize(value: KvCompression) =
        when (value) {
            is KvCompression.None -> {
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                (
                    4UL
                )
            }

            is KvCompression.TurboQuant -> {
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                (
                    4UL +
                        FfiConverterULong.allocationSize(value.`seed`) +
                        FfiConverterBoolean.allocationSize(value.`keys`) +
                        FfiConverterBoolean.allocationSize(value.`values`)
                )
            }
        }

    override fun write(
        value: KvCompression,
        buf: ByteBuffer,
    ) {
        when (value) {
            is KvCompression.None -> {
                buf.putInt(1)
                Unit
            }

            is KvCompression.TurboQuant -> {
                buf.putInt(2)
                FfiConverterULong.write(value.`seed`, buf)
                FfiConverterBoolean.write(value.`keys`, buf)
                FfiConverterBoolean.write(value.`values`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}

